const toggle=document.querySelector('.pref-menu-toggle');const nav=document.querySelector('.preferences-navi');const navUls=nav.querySelectorAll('ul');toggle.addEventListener('click',()=>{const isHidden=nav.classList.toggle('preferences-navi--hidden');nav.setAttribute('aria-expanded',!isHidden);navUls.forEach(ul=>{ul.setAttribute('tabindex',isHidden?'-1':'0');ul.setAttribute('aria-disabled',isHidden?'true':'false')});isHidden?toggle.removeAttribute('tabindex'):toggle.setAttribute('tabindex','-1')})